import React, { useEffect, useState } from 'react';
import { ProfileUser, Interest } from '../types';
import GlowButton from '../components/GlowButton';
import PageLayout from '../components/PageLayout';

const defaultUser: ProfileUser = {
  name: 'Your Name',
  email: 'you@example.com',
  profilePicture: null,
  preferences: {
    interests: [],
    indoorOutdoor: 'no-preference',
    budgetAmount: 500,
    radiusMiles: 3,
    weatherTolerance: { avoidRain: false, avoidExtremeHeat: false },
  },
  savedEvents: [],
  savedRestaurants: [],
};

// Activity interests used in profile (keeps app consistent)
const ALL_INTERESTS: Interest[] = [
  'Sports',
  'Food',
  'Breweries',
  'Nightlife',
  'Concerts',
  'Museums',
  'Parks',
  'Hotels',
];

const Profile: React.FC = () => {
  const [user, setUser] = useState<ProfileUser>(defaultUser);
  const [editing, setEditing] = useState(false);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [picturePreview, setPicturePreview] = useState<string | null>(null);
  const [prefs, setPrefs] = useState(defaultUser.preferences);

  useEffect(() => {
    const raw = localStorage.getItem('user');
    if (raw) {
      try {
        const parsed = JSON.parse(raw) as ProfileUser;
        // merge safely with defaults
        const merged: ProfileUser = { ...defaultUser, ...parsed };
        merged.preferences = { ...defaultUser.preferences, ...(parsed.preferences || {}) };
        setUser(merged);
        setName(merged.name);
        setEmail(merged.email);
        setPicturePreview(merged.profilePicture || null);
        setPrefs(merged.preferences);
      } catch {
        setUser(defaultUser);
        setName(defaultUser.name);
        setEmail(defaultUser.email);
        setPrefs(defaultUser.preferences);
      }
    } else {
      setUser(defaultUser);
      setName(defaultUser.name);
      setEmail(defaultUser.email);
      setPrefs(defaultUser.preferences);
    }
  }, []);

  const startEdit = () => {
    setEditing(true);
  };

  const cancelEdit = () => {
    setEditing(false);
    setName(user.name);
    setEmail(user.email);
    setPicturePreview(user.profilePicture || null);
  };

  const handleFile = (ev: React.ChangeEvent<HTMLInputElement>) => {
    const file = ev.target.files && ev.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => {
      const result = reader.result as string;
      setPicturePreview(result);
    };
    reader.readAsDataURL(file);
  };

  const toggleInterest = (interest: Interest) => {
    const next = prefs.interests.includes(interest)
      ? prefs.interests.filter((i) => i !== interest)
      : [...prefs.interests, interest];
    const updated = { ...prefs, interests: next };
    setPrefs(updated);
  };

  const setIndoorOutdoor = (value: ProfileUser['preferences']['indoorOutdoor']) => {
    setPrefs({ ...prefs, indoorOutdoor: value });
  };

  // budgetAmount handled via slider with adaptive stepping
  const setBudgetAmount = (amount: number) => {
    setPrefs({ ...prefs, budgetAmount: amount });
  };

  const setRadius = (miles: number) => {
    setPrefs({ ...prefs, radiusMiles: miles });
  };

  const handleBudgetChange = (rawValue: number) => {
    // Round to nearest 50 up to 1000, then to nearest 1000 thereafter
    const rounded = rawValue <= 1000 ? Math.round(rawValue / 50) * 50 : Math.round(rawValue / 1000) * 1000;
    setBudgetAmount(Math.max(0, Math.min(50000, rounded)));
  };

  const adjustBudget = (deltaSign: 1 | -1) => {
    const current = prefs.budgetAmount || 0;
    const step = current < 1000 ? 50 : 1000;
    let next = current + deltaSign * step;
    // If crossing the 1000 boundary downward, snap appropriately
    if (deltaSign < 0 && current > 1000 && next < 1000) {
      next = Math.max(0, Math.round(next / 50) * 50);
    }
    next = Math.max(0, Math.min(50000, next));
    setBudgetAmount(next);
  };

  const adjustRadius = (deltaSign: 1 | -1) => {
    const current = prefs.radiusMiles || 1;
    const next = Math.max(1, Math.min(50, current + deltaSign));
    setRadius(next);
  };

  const toggleWeather = (key: keyof ProfileUser['preferences']['weatherTolerance']) => {
    setPrefs({ ...prefs, weatherTolerance: { ...prefs.weatherTolerance, [key]: !prefs.weatherTolerance[key] } });
  };

  const saveAll = () => {
    const updated: ProfileUser = {
      ...user,
      name: name.trim() || 'Unnamed',
      email: email.trim() || 'no-reply@example.com',
      profilePicture: picturePreview,
      preferences: prefs,
    };
    setUser(updated);
    localStorage.setItem('user', JSON.stringify(updated));
    setEditing(false);
  };

  const removeSavedEvent = (id: string) => {
    const next = user.savedEvents.filter((s) => s.id !== id);
    const updated = { ...user, savedEvents: next };
    setUser(updated);
    localStorage.setItem('user', JSON.stringify(updated));
  };

  const removeSavedRestaurant = (id: string) => {
    const next = user.savedRestaurants.filter((s) => s.id !== id);
    const updated = { ...user, savedRestaurants: next };
    setUser(updated);
    localStorage.setItem('user', JSON.stringify(updated));
  };

  return (
    <PageLayout className="min-h-screen">
    <div className="glass-card mx-auto w-full max-w-5xl rounded-[2rem] p-8 sm:p-10">
      <h1 className="section-title mb-10 text-center text-white">Profile</h1>

      <div className="grid gap-10 md:grid-cols-3 md:items-start">
        <div className="md:col-span-1 flex justify-center md:justify-start">
        <div className="flex h-44 w-44 items-center justify-center rounded-full border border-[#D4AF37]/35 bg-[#F1E7C8]/80 p-1 shadow-[0_0_0_1px_rgba(241,231,200,0.12),0_0_28px_rgba(212,175,55,0.2)] overflow-hidden">
          <div className="flex h-full w-full items-center justify-center overflow-hidden rounded-full bg-[#F1E7C8]/85">
          {picturePreview ? (
            <img src={picturePreview} alt="avatar" className="w-full h-full object-cover" />
          ) : (
            <div className="text-[#2B2B2B]">No Photo</div>
          )}
        </div>
        </div>
        </div>

        <div className="md:col-span-2 text-white">
          {!editing ? (
            <div className="space-y-8">
              <div className="space-y-2">
                <p className="text-3xl font-semibold tracking-tight text-white">{user.name}</p>
                <p className="text-base text-white/72">{user.email}</p>
              </div>

              <div className="space-y-2">
                <h3 className="text-sm uppercase tracking-[0.24em] text-white/62">Preferences</h3>
                <div className="mt-1 space-y-1.5 text-xs text-white/60">
                  Interests: {user.preferences.interests.join(', ') || '—'}
                  <div>Indoor/Outdoor: {user.preferences.indoorOutdoor}</div>
                  <div>Budget: {user.preferences.budgetAmount ? new Intl.NumberFormat('en-US',{style:'currency',currency:'USD',maximumFractionDigits:0}).format(user.preferences.budgetAmount) : '—'}</div>
                  <div>Radius: {user.preferences.radiusMiles} miles</div>
                  <div>Avoid Rain: {user.preferences.weatherTolerance.avoidRain ? 'Yes' : 'No'}</div>
                  <div>Avoid Extreme Heat: {user.preferences.weatherTolerance.avoidExtremeHeat ? 'Yes' : 'No'}</div>
                </div>
              </div>

              <div>
                <GlowButton
                  onClick={startEdit}
                  className="px-8 py-3"
                >
                  Edit Profile
                </GlowButton>
              </div>

              <div className="space-y-10 pt-2">
              <div>
                <h3 className="mb-3 text-lg font-semibold text-white">Saved Events</h3>
                {user.savedEvents.length === 0 ? (
                  <div className="text-white/55">No saved events</div>
                ) : (
                  <ul className="space-y-2">
                    {user.savedEvents.map((e) => (
                      <li key={e.id} className="flex items-center justify-between rounded-xl border border-white/10 bg-white/[0.04] p-3">
                        <span className="text-white">{e.name}</span>
                        <button onClick={() => removeSavedEvent(e.id)} className="text-sm text-gold hover:text-bone-white">Remove</button>
                      </li>
                    ))}
                  </ul>
                )}
              </div>

              <div>
                <h3 className="mb-3 text-lg font-semibold text-white">Saved Restaurants</h3>
                {user.savedRestaurants.length === 0 ? (
                  <div className="text-white/55">No saved restaurants</div>
                ) : (
                  <ul className="space-y-2">
                    {user.savedRestaurants.map((r) => (
                      <li key={r.id} className="flex items-center justify-between rounded-xl border border-white/10 bg-white/[0.04] p-3">
                        <span className="text-white">{r.name}</span>
                        <button onClick={() => removeSavedRestaurant(r.id)} className="text-sm text-gold hover:text-bone-white">Remove</button>
                      </li>
                    ))}
                  </ul>
                )}
              </div>
              </div>
            </div>
          ) : (
            <div className="space-y-6 text-white">
              <label className="block">
                <div className="mb-1 text-sm font-medium text-white/82">Name</div>
                <input
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="premium-input"
                />
              </label>

              <label className="block">
                <div className="mb-1 text-sm font-medium text-white/82">Email</div>
                <input
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="premium-input"
                />
              </label>

              <label className="block">
                <div className="mb-1 text-sm font-medium text-white/82">Profile Picture</div>
                <input className="text-sm text-white/75 file:mr-3 file:rounded-xl file:border-0 file:bg-white/10 file:px-3 file:py-2 file:text-white" type="file" accept="image/*" onChange={handleFile} />
              </label>

              <div className="pt-2">
                <h4 className="font-semibold text-white">Activity interests</h4>
                <div className="flex gap-2 flex-wrap mt-2">
                  {ALL_INTERESTS.map((i) => (
                    <label key={i} className={`rounded-xl border px-3 py-1.5 text-sm ${prefs.interests.includes(i) ? 'border-emerald/55 bg-emerald/20 text-white' : 'border-white/12 bg-white/[0.04] text-white/78'}`}>
                      <input className="mr-2" type="checkbox" checked={prefs.interests.includes(i)} onChange={() => toggleInterest(i)} />
                      {i}
                    </label>
                  ))}
                </div>
              </div>

              <div className="pt-4">
                <h4 className="font-semibold">Indoor vs Outdoor</h4>
                <div className="flex gap-3 mt-2">
                  <label className="text-white/82">
                    <input type="radio" name="indoorOutdoor" checked={prefs.indoorOutdoor === 'indoor'} onChange={() => setIndoorOutdoor('indoor')} /> Indoor
                  </label>
                  <label className="text-white/82">
                    <input type="radio" name="indoorOutdoor" checked={prefs.indoorOutdoor === 'outdoor'} onChange={() => setIndoorOutdoor('outdoor')} /> Outdoor
                  </label>
                  <label className="text-white/82">
                    <input type="radio" name="indoorOutdoor" checked={prefs.indoorOutdoor === 'no-preference'} onChange={() => setIndoorOutdoor('no-preference')} /> No preference
                  </label>
                </div>
              </div>

              <div className="pt-4">
                <h4 className="font-semibold">Budget</h4>
                <div className="mt-2 flex items-center gap-3">
                  <button
                    type="button"
                    onClick={() => adjustBudget(-1)}
                    aria-label="decrease budget"
                    className="rounded-xl border border-white/12 bg-white/[0.04] px-3 py-1 text-white"
                  >
                    −
                  </button>

                  <input
                    type="range"
                    min={0}
                    max={50000}
                    value={prefs.budgetAmount}
                    onChange={(e) => handleBudgetChange(Number(e.target.value))}
                    className="flex-1"
                  />

                  <button
                    type="button"
                    onClick={() => adjustBudget(1)}
                    aria-label="increase budget"
                    className="rounded-xl border border-white/12 bg-white/[0.04] px-3 py-1 text-white"
                  >
                    +
                  </button>

                  <div className="w-40 text-sm text-white text-right">
                    {new Intl.NumberFormat('en-US',{style:'currency',currency:'USD',maximumFractionDigits:0}).format(prefs.budgetAmount)}
                  </div>
                </div>
                <div className="mt-2 text-xs text-white/55">Tip: increments are $50 up to $1,000, then $1,000 increments thereafter.</div>
              </div>

              <div className="pt-4">
                <h4 className="font-semibold">Preferred travel radius</h4>
                <div className="mt-2 flex items-center gap-4">
                  <button type="button" onClick={() => adjustRadius(-1)} aria-label="decrease radius" className="rounded-xl border border-white/12 bg-white/[0.04] px-3 py-1 text-white">−</button>

                  <input
                    type="range"
                    min={1}
                    max={50}
                    value={prefs.radiusMiles}
                    onChange={(e) => setRadius(parseInt(e.target.value, 10))}
                    className="flex-1"
                  />

                  <button type="button" onClick={() => adjustRadius(1)} aria-label="increase radius" className="rounded-xl border border-white/12 bg-white/[0.04] px-3 py-1 text-white">+</button>

                  <div className="w-20 text-sm text-white text-right">{prefs.radiusMiles} mi</div>
                </div>
              </div>

              <div className="pt-4">
                <h4 className="font-semibold">Weather tolerance</h4>
                <div className="flex gap-4 mt-2 items-center">
                  <label className="flex items-center gap-2 text-white/82"><input type="checkbox" checked={prefs.weatherTolerance.avoidRain} onChange={() => toggleWeather('avoidRain')} /> Avoid Rain</label>
                  <label className="flex items-center gap-2 text-white/82"><input type="checkbox" checked={prefs.weatherTolerance.avoidExtremeHeat} onChange={() => toggleWeather('avoidExtremeHeat')} /> Avoid Extreme Heat</label>
                </div>
              </div>

              <div className="flex gap-3 pt-2">
                <GlowButton onClick={saveAll} className="px-8 py-3">Save</GlowButton>
                <button onClick={cancelEdit} className="rounded-full border border-white/20 bg-white/[0.06] px-6 py-3 text-sm font-semibold uppercase tracking-[0.14em] text-white/85 hover:bg-white/[0.12]">Cancel</button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
    </PageLayout>
  );
};

export default Profile;
